@namespace sv_3651630036f54c0e927791bd68403b62.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)"
                @onclick:stopPropagation="true"
                title="@emoji">
            @emoji
        </button>
    }
</div>

[Parameter, EditorRequired]
public EventCallback<string> OnEmojiSelected { get; set; }

@code {
    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🚀"];
}

@namespace sv_3651630036f54c0e927791bd68403b62.Components.Chat

<div class="message-bubble @(IsHighlighted ? "highlighted" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="HandleMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            💬 @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" @onclick:stopPropagation="true" title="Add reaction">
                😊 React
            </button>
        </div>

        @if (_showEmojiPicker)
        {
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        }
    }
</div>

@code {
    [Parameter, EditorRequired]
    public required Message Message { get; set; }

    [Parameter]
    public int ThreadReplyCount { get; set; }

    [Parameter]
    public bool IsHighlighted { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<string> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void HandleMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

