@namespace sv_3651630036f54c0e927791bd68403b62.Components.Chat

<aside class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name"># @channel.Name</div>
                <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </li>
        }
    </ul>
</aside>

@code {
    [Parameter, EditorRequired]
    public required List<Channel> Channels { get; set; }

    [Parameter]
    public int ActiveChannelId { get; set; }

    [Parameter]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string desc) =>
        desc.Length > 50 ? desc[..47] + "..." : desc;
}

@namespace sv_3651630036f54c0e927791bd68403b62.Components.Chat
@inject IJSRuntime JS

<section class="message-area">
    <header class="message-area-header">
        @if (Channel is not null)
        {
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        }
    </header>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }

        @if (HasMoreMessages && !IsLoadingMore)
        {
            <div class="load-more-hint">Scroll up to load more</div>
        }

        @foreach (var message in Messages)
        {
            @if (message.ReplyToId is null)
            {
                <MessageBubble Message="message"
                               ThreadReplyCount="GetThreadReplyCount(message.Id)"
                               OnOpenThread="OnOpenThread"
                               OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
            }
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-input"
                  @bind="NewMessageText"
                  @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Type a message..."
                  rows="2"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">
            Send
        </button>
    </div>
</section>

@code {
    [Parameter, EditorRequired]
    public required List<Message> Messages { get; set; }

    [Parameter]
    public Channel? Channel { get; set; }

    [Parameter]
    public List<ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter]
    public bool HasMoreMessages { get; set; }

    [Parameter]
    public bool IsLoadingMore { get; set; }

    [Parameter]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private string NewMessageText { get; set; } = "";

    private int GetThreadReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        if (IsLoadingMore || !HasMoreMessages) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(NewMessageText)) return;
        var text = NewMessageText;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }
}

@namespace sv_3651630036f54c0e927791bd68403b62.Components.Chat

<aside class="thread-panel">
    <header class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </header>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <MessageBubble Message="RootMessage" OnReact="(emoji) => OnReact.InvokeAsync((RootMessage.Id, emoji))" />
        </div>

        <hr class="thread-divider" />

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageBubble Message="reply" OnReact="(emoji) => OnReact.InvokeAsync((reply.Id, emoji))" />
            }
        </div>

        <div class="thread-input-area">
            <textarea class="thread-input"
                      @bind="ReplyText"
                      @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Reply in thread..."
                      rows="2"></textarea>
            <button class="send-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(ReplyText)">
                Reply
            </button>
        </div>
    }
</aside>

@code {
    [Parameter, EditorRequired]
    public required Message RootMessage { get; set; }

    [Parameter]
    public List<Message> Replies { get; set; } = [];

    [Parameter]
    public EventCallback OnClose { get; set; }

    [Parameter]
    public EventCallback<string> OnSendReply { get; set; }

    [Parameter]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private string ReplyText { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(ReplyText)) return;
        var text = ReplyText;
        ReplyText = "";
        await OnSendReply.InvokeAsync(text);
    }
}

