                     OnReact="HandleReaction" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private int _activeChannelId;
    private Channel? _activeChannel;

    // Thread state
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];
    private bool IsThreadOpen => _threadRootMessage is not null;

    // Pagination state
    private bool _hasMoreMessages = true;
    private bool _isLoadingMore;
    private int _currentSkip;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _currentSkip = 0;
        _hasMoreMessages = true;
        _threadRootMessage = null;
        _threadReplies = [];

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _currentSkip = _messages.Count;
        _hasMoreMessages = _messages.Count == PageSize;

        await ChatService.MarkChannelReadAsync(channelId);
        await RefreshChannels();
        BuildThreadSummaries();
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages) return;
        _isLoadingMore = true;

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _currentSkip, PageSize);
        _messages.InsertRange(0, older);
        _currentSkip += older.Count;
        _hasMoreMessages = older.Count == PageSize;
        _isLoadingMore = false;

        BuildThreadSummaries();
    }

